// Good: using a PreparedStatement to safely parameterize user input
public void getUserInfo(HttpServletRequest request) throws SQLException {
    // Retrieve the user id from the request (still no validation, but safe for SQL)
    String userId = request.getParameter("id");

    // Use a prepared statement to avoid SQL injection
    String sql = "SELECT * FROM users WHERE id = ?";
    try (Connection conn = DriverManager.getConnection(DB_URL, USER, PASS);
         PreparedStatement pstmt = conn.prepareStatement(sql)) {

        // Set the parameter value safely
        pstmt.setString(1, userId);

        try (ResultSet rs = pstmt.executeQuery()) {
            while (rs.next()) {
                // Process result set
                System.out.println("User: " + rs.getString("username"));
            }
        }
    }
}
